import{_ as a,o as t,c as r,a0 as i}from"./chunks/framework.DTwdCQre.js";const c=JSON.parse('{"title":"API 错误","description":"AI 提供商的 API 错误处理与解决方案","frontmatter":{"title":"API 错误","description":"AI 提供商的 API 错误处理与解决方案"},"headers":[],"relativePath":"zh/troubleshooting/api-errors.md","filePath":"zh/troubleshooting/api-errors.md","lastUpdated":1777727293000}'),o={name:"zh/troubleshooting/api-errors.md"};function l(n,e,s,d,u,p){return t(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="api-错误" tabindex="-1">API 错误 <a class="header-anchor" href="#api-错误" aria-label="Permalink to &quot;API 错误&quot;">​</a></h1><p>处理来自 AI 提供商的错误。</p><h2 id="速率限制" tabindex="-1">速率限制 <a class="header-anchor" href="#速率限制" aria-label="Permalink to &quot;速率限制&quot;">​</a></h2><h3 id="rate-limit-exceeded" tabindex="-1">&quot;rate_limit_exceeded&quot; <a class="header-anchor" href="#rate-limit-exceeded" aria-label="Permalink to &quot;&quot;rate_limit_exceeded&quot;&quot;">​</a></h3><p><strong>原因</strong>: 请求过于频繁。</p><p><strong>解决方案</strong>:</p><ul><li>等待 60 秒后重试</li><li>升级您的套餐</li><li>降低请求频率</li></ul><h3 id="rate-limit-request-enqueued" tabindex="-1">&quot;rate_limit_request_enqueued&quot; <a class="header-anchor" href="#rate-limit-request-enqueued" aria-label="Permalink to &quot;&quot;rate_limit_request_enqueued&quot;&quot;">​</a></h3><p><strong>原因</strong>: 因负载过高，请求被排队。</p><p><strong>解决方案</strong>:</p><ul><li>等待自动重试</li><li>减少并发请求数</li></ul><h2 id="认证错误" tabindex="-1">认证错误 <a class="header-anchor" href="#认证错误" aria-label="Permalink to &quot;认证错误&quot;">​</a></h2><h3 id="invalid-api-key" tabindex="-1">&quot;invalid_api_key&quot; <a class="header-anchor" href="#invalid-api-key" aria-label="Permalink to &quot;&quot;invalid_api_key&quot;&quot;">​</a></h3><p><strong>原因</strong>: API 密钥错误。</p><p><strong>解决方案</strong>:</p><ul><li>检查密钥格式 (sk-ant-...)</li><li>生成新密钥</li><li>验证配置中的密钥</li></ul><h3 id="permission-denied" tabindex="-1">&quot;permission_denied&quot; <a class="header-anchor" href="#permission-denied" aria-label="Permalink to &quot;&quot;permission_denied&quot;&quot;">​</a></h3><p><strong>原因</strong>: 密钥缺少所需权限。</p><p><strong>解决方案</strong>:</p><ul><li>检查密钥作用域</li><li>使用正确的权限生成密钥</li><li>联系 Anthropic 支持</li></ul><h2 id="内容错误" tabindex="-1">内容错误 <a class="header-anchor" href="#内容错误" aria-label="Permalink to &quot;内容错误&quot;">​</a></h2><h3 id="context-length-exceeded" tabindex="-1">&quot;context_length_exceeded&quot; <a class="header-anchor" href="#context-length-exceeded" aria-label="Permalink to &quot;&quot;context_length_exceeded&quot;&quot;">​</a></h3><p><strong>原因</strong>: 上下文过长。</p><p><strong>解决方案</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /compact</span></span>
<span class="line"><span>&gt; 让我们使用压缩后的上下文继续</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="invalid-request-error" tabindex="-1">&quot;invalid_request_error&quot; <a class="header-anchor" href="#invalid-request-error" aria-label="Permalink to &quot;&quot;invalid_request_error&quot;&quot;">​</a></h3><p><strong>原因</strong>: 请求格式错误。</p><p><strong>解决方案</strong>:</p><ul><li>更新到最新版本</li><li>检查 settings.json 格式</li><li>如持续出现，请报告错误</li></ul><h2 id="服务器错误" tabindex="-1">服务器错误 <a class="header-anchor" href="#服务器错误" aria-label="Permalink to &quot;服务器错误&quot;">​</a></h2><h3 id="api-error-或-server-error" tabindex="-1">&quot;api_error&quot; 或 &quot;server_error&quot; <a class="header-anchor" href="#api-error-或-server-error" aria-label="Permalink to &quot;&quot;api_error&quot; 或 &quot;server_error&quot;&quot;">​</a></h3><p><strong>原因</strong>: 提供商服务器问题。</p><p><strong>解决方案</strong>:</p><ul><li>等待后重试</li><li>检查提供商状态页面</li><li>尝试其他模型</li></ul><h2 id="重试逻辑" tabindex="-1">重试逻辑 <a class="header-anchor" href="#重试逻辑" aria-label="Permalink to &quot;重试逻辑&quot;">​</a></h2><p>claude-code-Go 会自动重试:</p><ul><li>速率限制（使用指数退避）</li><li>超时（最多 3 次尝试）</li><li>服务器错误（5xx）</li></ul><p>手动重试:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; 执行失败了，请重试一次</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p>英文版本: <a href="/claude-code-Go/troubleshooting/api-errors.html">API Errors</a></p></blockquote>`,40)])])}const q=a(o,[["render",l]]);export{c as __pageData,q as default};
